questions.question:
Which one of the choices given below would be printed when the following program is executed?

#include <stdio.h>
int a1[] = {6, 7, 8, 18, 34, 67};
int a2[] = {23, 56, 28, 29};
int a3[] = {-12, 27, -31};
int *x[] = {a1, a2, a3};
void print(int *a[])
{
    printf("%d,", a[0][2]);
    printf("%d,", *a[2]);
    printf("%d,", a[2][1]);
    printf("%d,", *(a[1]+3));
}
main()
{
    print(x);
}

A. 8, -12, 27, 29
B. 8, -12, 27, 56
C. -12, -13, 27, -31, 23
D. -12, -12, 27, -31, 56

Consider the C program given below:

#include <stdio.h>
int main()
{
    int sum = 0, maxsum = 0, i, n = 6;
    int a[] = {2, -2, -1, 3, 4, 2};
    for (i = 0; i < n; i++)
    {
        if (i == 0 || a[i] < 0 || a[i] < a[i-1])
        {
            if (sum > maxsum)
                maxsum = sum;
            sum = (a[i] > 0) ? a[i] : 0;
        }
        else
            sum += a[i];
    }
    if (sum > maxsum)
        maxsum = sum;
    printf("%d", maxsum);
    return 0;
}

What is the value printed out when this program is executed?

A. 9
B. 8
C. 7
D. 6
